import type { ScaleTime } from 'd3-scale';

import { AxisBottom } from '../AxisBottom.js';
import { axisFontProps } from '../constants.js';
import { DivAxisWrapper } from './DivAxisWrapper.js';
import {
  bottomPanTickLabelDateProps,
  bottomTickLabelDateProps,
} from '../utils/get-tick-label-props.js';

/**
 * @internal
 */
export interface TimeBottomAxisProps {
  scale: ScaleTime<number, number>;
  containerWidth: number;
  containerHeight: number;
  label?: string;
  stroke?: string;
  ticks: string[];
  tickColor?: string;
  formattedTicks: string[];
  shrinkTickEdges?: boolean;
}

/**
 * @internal
 */
export const TimeBottomAxis = (props: TimeBottomAxisProps) => {
  const {
    scale,
    containerWidth,
    containerHeight,
    label,
    stroke,
    ticks,
    tickColor,
    formattedTicks,
    shrinkTickEdges,
  } = props;

  const tickFormat = (_: unknown, index: number) => formattedTicks[index];

  return (
    <DivAxisWrapper
      divAxisStyle={axisFontProps}
      ticks={formattedTicks}
      label={label}
      isTickVertical
    >
      <AxisBottom
        role="graphics-symbol"
        aria-label="time axis bottom"
        scale={scale}
        containerSize={containerWidth}
        height={containerHeight}
        tickValues={ticks}
        tickLabelProps={
          shrinkTickEdges
            ? bottomPanTickLabelDateProps
            : bottomTickLabelDateProps
        }
        tickFormat={tickFormat}
        tickColor={tickColor}
        label={label}
        stroke={stroke}
      />
    </DivAxisWrapper>
  );
};

TimeBottomAxis['displayName'] = 'TimeBottomAxis';
